/** Shared shipment milestone logic (list + parcel detail). */

import {
  THAI_POST_STATUS_META,
  type ThaiPostStatusCode,
} from "@quickload/shared/thai-post-status";
import { thaiPostStatusDateToMs } from "@quickload/shared/thai-post-webhook-history";

export function effectiveLogisticsStatus(parcel: { status: string; isPaid: boolean }): string {
  if (parcel.isPaid && (parcel.status === "pending_payment" || parcel.status === "awaiting_actual_weight")) {
    return "paid";
  }
  return parcel.status;
}

/** Single “representative” ปณ. code (1–20) for list UI when webhook history is not loaded. */
export function representativeThaiPostCodeNum(parcel: { status: string; isPaid: boolean }): number {
  const s = effectiveLogisticsStatus(parcel);
  const map: Record<string, number> = {
    draft: 0,
    awaiting_actual_weight: 0,
    pending_payment: 1,
    paid: 3,
    registered: 3,
    in_transit: 5,
    returning: 10,
    at_destination_post: 6,
    delivered: 7,
    failed: 15,
    canceled: 20,
  };
  return map[s] ?? 0;
}

/**
 * Macro phases (legacy PHP modal): 4 steps, highlight by keyword rules on ปณ. description
 * (รับฝาก / คัดแยก+ขนส่ง / เตรียมนำจ่าย+ปลายทาง / นำจ่ายสำเร็จ).
 */
const MACRO_PHASES: { label: string; test: (descriptionTh: string) => boolean }[] = [
  {
    label: "เข้าระบบ",
    test: (d) =>
      d.includes("รับฝาก") || d.includes("ฝากแล้ว") || d.includes("ต้นทางรับ"),
  },
  {
    label: "ระหว่างขนส่ง",
    test: (d) =>
      d.includes("คัดแยก") ||
      d.includes("ขนส่ง") ||
      d.includes("สแกน") ||
      d.includes("ส่งออกจากศูนย์") ||
      d.includes("ถึงศูนย์คัดแยก"),
  },
  {
    label: "ออกนำไปจ่าย",
    test: (d) =>
      d.includes("เตรียมนำจ่าย") ||
      d.includes("ออกใบแจ้ง") ||
      d.includes("รอจ่าย ณ") ||
      (d.includes("ถึง") && d.includes("ปลายทาง")),
  },
  {
    label: "นำจ่ายสำเร็จ",
    test: (d) => d.includes("นำจ่ายถึงผู้รับแล้ว") || d.includes("นำจ่าย/ชำระเงินเรียบร้อย"),
  },
];

