export function macroPhaseMaxFromDescription(descriptionTh: string): number {
  let max = 0;
  MACRO_PHASES.forEach((phase, i) => {
    if (phase.test(descriptionTh)) max = Math.max(max, i + 1);
  });
  return max;
}

export type ListParcelThaiPostWebhookRow = {
  id: string;
  barcode?: string | null;
  statusCode: string;
  description: string | null;
  statusDateRaw: string | null;
  createdAt: string;
  station?: string | null;
};

function normalizeThaiPostCodeNum(raw: string): number {
  const n = Number(String(raw).trim());
  if (!Number.isFinite(n) || n < 1 || n > 20) return 0;
  return Math.trunc(n);
}

/** Visual language for webhook rows: dot, code pill, optional caption. */
function thaiPostWebhookRowAccent(codeNum: number): {
  dot: string;
  dotRing: string;
  pill: string;
  caption: string | null;
} {
  if (codeNum === 2 || codeNum === 7) {
    return {
      dot: "bg-emerald-500",
      dotRing: "ring-emerald-200/90",
      pill: "bg-emerald-600 text-white shadow-sm shadow-emerald-900/10",
      caption: "สำเร็จ",
    };
  }
  if (codeNum >= 15 && codeNum <= 19) {
    return {
      dot: "bg-rose-500",
      dotRing: "ring-rose-200/90",
      pill: "bg-rose-600 text-white shadow-sm shadow-rose-900/10",
      caption: "ต้องติดตาม",
    };
  }
  if (codeNum === 20) {
    return {
      dot: "bg-slate-400",
      dotRing: "ring-slate-200",
      pill: "bg-slate-600 text-white shadow-sm",
      caption: "ยกเลิก",
    };
  }
  if (codeNum === 10) {
    return {
      dot: "bg-amber-500",
      dotRing: "ring-amber-200/90",
      pill: "bg-amber-600 text-white shadow-sm shadow-amber-900/10",
      caption: "ส่งคืน",
    };
  }
  if (codeNum >= 1 && codeNum <= 20) {
    return {
      dot: "bg-indigo-70",
      dotRing: "ring-indigo-200/80",
      pill: "bg-indigo-600 text-white shadow-sm shadow-indigo-900/10",
      caption: null,
    };
  }
  return {
    dot: "bg-slate-400",
    dotRing: "ring-slate-200",
    pill: "bg-slate-700 text-white shadow-sm",
    caption: null,
  };
}

function formatThaiPostWebhookRowTime(statusDateRaw: string | null, createdAt: string): string {
  const raw = statusDateRaw?.trim();
  if (raw) return raw;
  const d = new Date(createdAt);
  if (Number.isNaN(d.getTime())) return "—";
  return d.toLocaleString("th-TH", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
}

export function shipmentProgressStep(status: string): number {
  switch (status) {
    case "draft":
    case "awaiting_actual_weight":
      return 0;
    case "pending_payment":
      return 1;
    case "paid":
    case "registered":
    case "in_transit":
    case "returning":
      return 2;
    case "at_destination_post":
      return 3;
    case "delivered":
      return 4;
    case "failed":
      return 2;
    case "canceled":
      return 0;
    default:
      return 1;
  }
}

export const SHIPMENT_PROGRESS_LABELS_TH = [
  "รอฝากพัสดุที่ไปรษณีย์",
  "รับฝากแล้ว · รอชำระค่าส่ง",
  "ระหว่างขนส่ง",
  "ถึงปลายทาง · รอนำจ่าย",
  "นำจ่ายถึงผู้รับแล้ว",
] as const;

/** Premium timeline for Thailand Post webhook history (list expander + parcel detail). */
export function ThaiPostWebhookHistoryCard({
  events,
  framed = true,
  compact = false,
  showHeader = true,
  title = "ประวัติสถานะจาก webhook",
  subtitle = "ไปรษณีย์ไทย · เรียงตามเวลาที่ระบุจากผู้ให้บริการ",
}: {
  events: ListParcelThaiPostWebhookRow[];
  framed?: boolean;
  compact?: boolean;
  showHeader?: boolean;
  title?: string;
  subtitle?: string;
}) {
  const chronological = [...events].sort((a, b) => {
    const ta = thaiPostStatusDateToMs(a.statusDateRaw) ?? new Date(a.createdAt).getTime();
    const tb = thaiPostStatusDateToMs(b.statusDateRaw) ?? new Date(b.createdAt).getTime();
    if (ta !== tb) return ta - tb;
    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
  });
  const latestEvent = chronological.length > 0 ? chronological[chronological.length - 1] : null;
  const latestCodeNum = latestEvent ? normalizeThaiPostCodeNum(latestEvent.statusCode) : 0;
  const latestMeta =
    latestCodeNum > 0 ? THAI_POST_STATUS_META[String(latestCodeNum) as ThaiPostStatusCode] : null;
  const latestBarcode = latestEvent?.barcode?.trim() || null;
  const latestStatusText = latestEvent?.description?.trim() || latestMeta?.descriptionTh || null;
  const headerTitle = latestBarcode ? `${latestBarcode}${latestStatusText ? ` (${latestStatusText})` : ""}` : title;

  const pad = compact ? "px-3 py-3.5" : "px-3 py-3.5 sm:px-4 sm:py-3";
  const headerPad = compact ? "px-3 py-2.5" : "px-4 py-3.5";

  const body =
    chronological.length === 0 ? (
      <div
        className={`text-center ${framed ? "border-b border-slate-100/80 bg-gradient-to-b from-slate-50/70 to-white" : "rounded-md border border-slate-200/90 bg-gradient-to-b from-slate-50/80 to-white shadow-[0_1px_3px_rgba(15,23,42,0.05)]"} ${compact ? "px-4 py-5" : "px-4 py-5"}`}
      >
        <p className="text-sm font-medium text-slate-700">โปรดนำพัสดุไปลงทะเบียนที่สาขาไปรษณีย์ไทยใกล้บ้านคุณ</p>
        <a href="https://postbase.thailandpost.co.th/th/service-point" target="_blank" rel="noopener" className="text-[#2726F5] underline text-xs">ค้นหาสาขาไปรษณีย์ไทยใกล้บ้าน</a>
      </div>
    ) : (
      <>
        {showHeader ? (
          <div
            className={`border-b border-slate-100/90 bg-gradient-to-br from-slate-50/90 via-white to-indigo-50/25 ${headerPad}`}
          >
            <h3 className="text-sm font-medium tracking-tight text-slate-800">{headerTitle}</h3>
            <p className="text-[10px] font-normal leading-snug text-slate-400">{subtitle}</p>
          </div>
        ) : null}
        <ul className={pad}>
          {chronological.map((event, idx) => {
            const codeNum = normalizeThaiPostCodeNum(event.statusCode);
            const meta = codeNum > 0 ? THAI_POST_STATUS_META[String(codeNum) as ThaiPostStatusCode] : null;
            const label =
              event.description?.trim() || meta?.descriptionTh || "อัปเดตสถานะ";
            const isLatest = idx === chronological.length - 1;
            const accent = thaiPostWebhookRowAccent(codeNum);
            const timeStr = formatThaiPostWebhookRowTime(event.statusDateRaw, event.createdAt);
            const stationLine = event.station?.trim();
            return (
              <li key={`${event.id}-${idx}`} className="group relative">
                <div className="flex gap-4">
                  <div className="relative flex w-3 flex-col items-center">
                    <div
                      className={`relative z-10 flex h-3 w-3 items-center justify-center rounded-full mt-1 ${accent.dot} ${
                        isLatest
                          ? "bg-[#2726F5]"
                          : "shadow-[0_0_0_2px_white] ring-1 ring-slate-200 bg-white"
                      }`}
                      aria-hidden
                    />
                    {idx < chronological.length - 1 ? (
                      <div
                        className="absolute left-1/2 top-4 z-0 h-[calc(100%+1.25rem)] -translate-x-1/2 border-l border-dashed border-[#2726F5]/40 h-full"
                        aria-hidden
                      />
                    ) : null}
                  </div>

                  <div
                    className={`min-w-0 flex-1`}
                  >
                    <div className="flex items-start justify-between gap-3">
                      <div className="min-w-0 flex-1">
                        <h4
                          className={`mb-1 font-medium leading-snug ${
                            isLatest
                              ? "text-xs text-slate-800"
                              : "text-xs text-slate-800"
                          }`}
                        >
                          {label}
                        </h4>
                        {stationLine ? (
                          <div className="mb-4 flex items-center gap-1.5">
                            <svg
                              className="h-3.5 w-3.5 text-slate-400"
                              fill="none"
                              stroke="currentColor"
                              viewBox="0 0 24 24"
                              aria-hidden
                            >
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                            </svg>
                            <span className="text-[10px] text-slate-500">{stationLine}</span>
                          </div>
                        ) : null}
                      </div>
                      <div className="flex shrink-0 flex-col items-end text-right">
                        <time
                          className="mb-0.5 text-[10px] font-medium tabular-nums text-slate-500"
                          dateTime={event.statusDateRaw ?? undefined}
                        >
                          {timeStr}
                        </time>
                      </div>
                    </div>
                  </div>
                </div>
              </li>
            );
          })}
        </ul>
      </>
    );

  if (!framed) {
    return <div className="min-w-0">{body}</div>;
  }

  return (
    <div className="min-w-0 overflow-hidden rounded-lg border border-slate-200/90 bg-white shadow-[0_1px_3px_rgba(15,23,42,0.06),0_4px_12px_rgba(15,23,42,0.04)]">
      {body}
    </div>
  );
}

/** Parcels list: macro strip + vertical table of webhook-received ปณ. statuses only. */
export function ListParcelThaiPostProgressHorizontal({
  parcel,
}: {
  parcel: {
    status: string;
    isPaid: boolean;
    thaiPostEvents?: ListParcelThaiPostWebhookRow[];
  };
}) {
  const events = parcel.thaiPostEvents ?? [];
  const chronological = [...events].sort((a, b) => {
    const ta = thaiPostStatusDateToMs(a.statusDateRaw) ?? new Date(a.createdAt).getTime();
    const tb = thaiPostStatusDateToMs(b.statusDateRaw) ?? new Date(b.createdAt).getTime();
    if (ta !== tb) return ta - tb;
    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
  });
  const latest = chronological.length > 0 ? chronological[chronological.length - 1] : null;

  let rep = representativeThaiPostCodeNum(parcel);
  if (latest) {
    const fromHook = normalizeThaiPostCodeNum(latest.statusCode);
    if (fromHook > 0) rep = fromHook;
  }

  const descForMacro = latest?.description?.trim()
    ? latest.description.trim()
    : rep > 0
      ? THAI_POST_STATUS_META[String(rep) as ThaiPostStatusCode].descriptionTh
      : "";

  let macroMax = descForMacro ? macroPhaseMaxFromDescription(descForMacro) : 0;
  const failed = parcel.status === "failed";
  const canceled = parcel.status === "canceled";
  const returning = parcel.status === "returning";
  if (failed && rep >= 15) {
    macroMax = Math.max(macroMax, 2);
  }

  return (
    <div className="mt-2 bg-slate-100 rounded-lg p-4">
      {canceled ? (
        <p className="mb-2 rounded-lg bg-slate-100 px-2 py-1.5 text-[10px] font-medium text-slate-600">พัสดุยกเลิก (รหัส 20)</p>
      ) : null}
      {failed ? (
        <p className="mb-2 rounded-lg bg-rose-50 px-2 py-1.5 text-[10px] font-medium text-rose-800">
          มีปัญหาการนำจ่าย (รหัส {rep || "—"})
        </p>
      ) : null}
      {returning ? (
        <p className="mb-2 rounded-lg bg-orange-50 px-2 py-1.5 text-[10px] font-medium text-orange-900">อยู่ระหว่างส่งคืน</p>
      ) : null}

      <div className="w-full">
        <div className="flex w-full items-center">
          {MACRO_PHASES.map((phase, i) => {
            const stepNum = i + 1;
            const done = macroMax >= stepNum;
            const circleClass = done
              ? failed && stepNum === macroMax
                ? "border-rose-500 bg-rose-500 text-white"
                : "border-emerald-500 bg-emerald-500 text-white"
              : "border-slate-200 bg-white text-slate-400";
            const leftLineOn = macroMax >= stepNum;
            const rightLineOn = macroMax >= stepNum + 1;

            return (
              <div key={phase.label} className="flex min-w-0 flex-1 items-center">
                <div
                  className={`h-0.5 min-w-[2px] flex-1 ${i === 0 ? "opacity-0" : ""} ${leftLineOn ? "bg-emerald-300" : "bg-slate-200"}`}
                  aria-hidden
                />
                <div
                  className={`relative z-[1] flex h-8 w-8 shrink-0 items-center justify-center rounded-full border-1 ${circleClass}`}
                >
                  <span className="block h-5 w-5 [&>svg]:h-full [&>svg]:w-full">
                    <MacroPhaseIcon stepIndex={i} />
                  </span>
                </div>
                <div
                  className={`h-0.5 min-w-[2px] flex-1 ${i === MACRO_PHASES.length - 1 ? "opacity-0" : ""} ${rightLineOn ? "bg-emerald-300" : "bg-slate-200"}`}
                  aria-hidden
                />
              </div>
            );
          })}
        </div>
        <div className="mt-[6px] flex w-full">
          {MACRO_PHASES.map((phase, i) => {
            const stepNum = i + 1;
            const pending = macroMax < stepNum;
            return (
              <div key={`${phase.label}-lbl`} className="flex min-w-0 flex-1 flex-col items-center px-0.5">
                <p
                  className={`max-w-[4.5rem] mt-2 text-center text-xs font-normal leading-tight ${
                    pending ? "text-slate-400" : "text-slate-800"
                  }`}
                >
                  {phase.label}
                </p>
              </div>
            );
          })}
        </div>
      </div>

      <div className="mt-3">
        <ThaiPostWebhookHistoryCard events={chronological} compact />
      </div>
    </div>
  );
}

export function ParcelShipmentProgressTimeline({
  activeStep,
  status,
  latestDescription,
  latestMeta,
  compact = false,
}: {
  activeStep: number;
  status: string;
  latestDescription: string | null;
  latestMeta: string | null;
  compact?: boolean;
}) {
  const failed = status === "failed";
  const returning = status === "returning";
  const canceled = status === "canceled";

  const pb = compact ? "pb-3" : "pb-6";
  const circle = compact ? "h-6 w-6 text-[10px]" : "h-8 w-8 text-xs";
  const lineLeft = compact ? "left-[11px]" : "left-[15px]";
  const lineTop = compact ? "top-6" : "top-8";
  const labelCls = compact ? "text-xs font-semibold" : "text-sm font-semibold";

  return (
    <div className={compact ? "" : "mt-3"}>
      {canceled ? (
        <p className="rounded-lg bg-slate-100 px-3 py-2 text-xs font-medium text-slate-600">พัสดุถูกยกเลิกตามสถานะจากขนส่ง</p>
      ) : null}
      {failed ? (
        <p className="mb-3 rounded-lg bg-rose-50 px-3 py-2 text-xs font-medium text-rose-800">
          มีปัญหาการนำจ่าย — ดูรายละเอียดเพิ่มเติมได้ที่หน้ารายละเอียดพัสดุ
        </p>
      ) : null}
      {returning ? (
        <p className="mb-3 rounded-lg bg-orange-50 px-3 py-2 text-xs font-medium text-orange-900">พัสดุอยู่ระหว่างส่งคืนต้นทาง</p>
      ) : null}

      <ol className="relative space-y-0">
        {SHIPMENT_PROGRESS_LABELS_TH.map((label, i) => {
          const done = i < activeStep;
          const current = i === activeStep;
          const pending = i > activeStep;
          const circleClass = done
            ? "border-emerald-500 bg-emerald-500 text-white"
            : current
              ? failed
                ? "border-rose-500 bg-rose-500 text-white"
                : "border-[#2726F5] bg-[#2726F5] text-white"
              : "border-slate-200 bg-white text-slate-400";

          return (
            <li key={label} className={`relative flex gap-3 ${pb} last:pb-0`}>
              {i < SHIPMENT_PROGRESS_LABELS_TH.length - 1 ? (
                <span
                  className={`absolute ${lineTop} ${lineLeft} h-[calc(100%-0.5rem)] w-0.5 ${done ? "bg-emerald-200" : "bg-slate-100"}`}
                  aria-hidden
                />
              ) : null}
              <div
                className={`relative z-[1] flex shrink-0 items-center justify-center rounded-full border-2 font-bold ${circle} ${circleClass}`}
              >
                {done ? "✓" : i + 1}
              </div>
              <div className="min-w-0 flex-1 pt-0.5">
                <p className={`${labelCls} ${pending ? "text-slate-400" : "text-slate-900"}`}>{label}</p>
                {current && latestDescription ? (
                  <p className="mt-1 text-xs leading-relaxed text-slate-600">
                    <span className="font-medium text-slate-700">ล่าสุดจาก ปณ.: </span>
                    {latestDescription}
                    {latestMeta ? <span className="block text-slate-500">{latestMeta}</span> : null}
                  </p>
                ) : null}
              </div>
            </li>
          );
        })}
      </ol>
    </div>
  );
}
